INSERT INTO public.questions (exam, subject, subtopic, chapter, difficulty, question_text, options, correct_option, solution_text) VALUES ('SSC CGL', 'Reasoning', 'Verbal Reasoning', 'Series', 'medium', 'If 4 ⊕ 3 = 19 and 5 ⊕ 2 = 17, then 6 ⊕ 4 = ?', '["24","28","34","32"]'::jsonb, 2, 'Given :
If 4 ⊕ 3 = 19 and 5 ⊕ 2 = 17
Logic : (1st number × 2nd number) + (1st number + 2nd number) = 3rd number
For, 4 ⊕ 3 = 19
(4 × 3) + (4 + 3) = 12 + 7 = 19
For, 5 ⊕ 2 = 17
(5 × 2) + (5 + 2) = 10 + 7 = 17
Similarly,
6 ⊕ 4 = ?
(6 × 4) + (6 + 4) = 24 + 10 = 34
Thus, correct option is (c).');
