INSERT INTO public.questions (exam, subject, subtopic, chapter, difficulty, question_text, options, correct_option, solution_text) VALUES ('SSC CGL', 'Reasoning', 'Verbal Reasoning', 'Series', 'medium', 'Find the missing t erm in the series.
