INSERT INTO public.questions (exam, subject, subtopic, chapter, difficulty, question_text, options, correct_option, solution_text) VALUES ('SSC CGL', 'Reasoning', 'Verbal Reasoning', 'Series', 'medium', 'Which w ord cannot be formed fr om DEMOCRA CY?', '["READY","CORE","MAYOR","CAREER"]'::jsonb, 3, 'Given : DEMOCRA CY
