INSERT INTO public.questions (exam, subject, subtopic, chapter, difficulty, question_text, options, correct_option, solution_text) VALUES ('SSC CGL', 'Reasoning', 'Verbal Reasoning', 'Miscellaneous', 'medium', 'Identif y the similar addr ess:
12, Lak e View R oad, Anna Nagar , Chennai - 600040', '["12 Lake View R d Anna Nagar Chennai 600040","Anna Nagar, 12 Lake R oad, Chennai","12 Lake R oad, Chennai - 600004","21 Lake View R oad, Anna Nagar, Chennai"]'::jsonb, 0, 'Given:
