INSERT INTO public.questions (exam, subject, subtopic, chapter, difficulty, question_text, options, correct_option, solution_text) VALUES ('SSC CGL', 'Reasoning', 'Verbal Reasoning', 'Miscellaneous', 'medium', 'Statement :
Online education is exp anding rapidly; hence quality standar ds must be maintained.
Assumptions :
I. Online education affects learning out comes.
II. Quality contr ol is necessar y in education.', '["Only I","Only II","Both I and II","Neither I nor II"]'::jsonb, 2, 'Statement:
Online education is expanding rapidly; hence quality standards must be maintained.
Assumptions:
I. Online education affects learning outcomes.
The statement argues that because online education is expanding, quality standards must be maintained. This implies that online education does
have an impact on learning outcomes → Assumption I is implicit.
II. Quality control is necessary in education.
Saying that quality standards must be maintained clearly assumes that quality control is necessary in education → Assumption II is also implicit.
So, both I and II  are implicit.
Thus, correct option is (c).');
INSERT INTO public.questions (exam, subject, subtopic, chapter, difficulty, question_text, options, correct_option, solution_text) VALUES ('SSC CGL', 'Reasoning', 'Verbal Reasoning', 'Series', 'medium', 'If 8 $ 3 = 32 and 6 $ 4 = 30, then 5 $ 4 = ?', '["28","20","24","25"]'::jsonb, 3, 'Given :
