INSERT INTO public.questions (exam, subject, subtopic, chapter, difficulty, question_text, options, correct_option, solution_text) VALUES ('SSC CGL', 'English', 'English Language', 'Miscellaneous', 'medium', 'How does the p assage say digital platforms str engthen conformity ?
